from machine import Pin
import usocket as socket
import ustruct as struct
import json
import ubinascii

# Setup LED pin
led = Pin(2, Pin.OUT)

# WebSocket handshake response
def ws_handshake(client, headers):
    webkey = headers['Sec-WebSocket-Key']
    webkey_plus = webkey + '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
    webaccept = ubinascii.b2a_base64(struct.sha256(webkey_plus)).decode('utf-8').strip()
    client.send('HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                'Sec-WebSocket-Accept: {}\r\n\r\n'.format(webaccept))

# WebSocket message handling
def ws_message_handler(msg):
    try:
        data = json.loads(msg)
        if 'action' in data:
            if data['action'] == 'turn_on':
                led.on()
                return json.dumps({"status": "LED turned on"})
            elif data['action'] == 'turn_off':
                led.off()
                return json.dumps({"status": "LED turned off"})
    except Exception as e:
        return json.dumps({"error": str(e)})

# WebSocket server
def websocket_server():
    addr = socket.getaddrinfo('0.0.0.0', 80)[0]
    s = socket.socket()
    s.bind((addr))
    s.listen(1)
    print('Listening on', addr)

    while True:
        client, addr = s.accept()
        print('Client connected from', addr)
        
        headers = {}
        while True:
            line = client.recv(1024).decode('utf-8')
            if not line or line == '\r\n':
                break
            name, value = line.split(':', 1)
            headers[name.strip()] = value.strip()

        ws_handshake(client, headers)

        while True:
            try:
                # Receive WebSocket message
                msg = client.recv(1024)
                if not msg:
                    break

                # Decode the payload based on WebSocket framing
                msg_len = msg[1] & 127
                if msg_len == 126:
                    msg_len = struct.unpack('>H', msg[2:4])[0]
                    masks = msg[4:8]
                    data = bytearray(bytearray(msg[8:8+msg_len]) ^ masks[i & 3] for i in range(msg_len))
                elif msg_len == 127:
                    msg_len = struct.unpack('>Q', msg[2:10])[0]
                    masks = msg[10:14]
                    data = bytearray(bytearray(msg[14:14+msg_len]) ^ masks[i & 3] for i in range(msg_len))
                else:
                    masks = msg[2:6]
                    data = bytearray(bytearray(msg[6:6+msg_len]) ^ masks[i & 3] for i in range(msg_len))

                response = ws_message_handler(data.decode('utf-8'))
                # Send response back as a WebSocket frame
                client.send(struct.pack('B', 129) + struct.pack('B', len(response)) + response.encode('utf-8'))

            except OSError as e:
                break

        client.close()
        print('Client disconnected')

# Start WebSocket server
if __name__ == '__main__':
    websocket_server()